def max_area_of_island(grid):
    rows, cols = len(grid), len(grid[0])

    def dfs(r, c):
        if r < 0 or r >= rows or c < 0 or c >= cols or grid[r][c] == 0:
            return 0
        grid[r][c] = 0  # mark visited
        return 1 + dfs(r+1, c) + dfs(r-1, c) + dfs(r, c+1) + dfs(r, c-1)

    max_area = 0
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == 1:
                max_area = max(max_area, dfs(r, c))
    return max_area

def rectangle_union_area(rects):
    """rects: list of (x1, y1, x2, y2). Returns total area covered."""
    events = []
    for x1, y1, x2, y2 in rects:
        events.append((x1, 1, y1, y2))  # 1 = start
        events.append((x2, -1, y1, y2)) # -1 = end
    events.sort()

    active = []  # list of (y1, y2) for active rectangles
    prev_x = events[0][0]
    total = 0

    def active_y_length():
        if not active:
            return 0
        active.sort()
        length = 0
        cur_start, cur_end = active[0]
        for s, e in active[1:]:
            if s <= cur_end:
                cur_end = max(cur_end, e)
            else:
                length += cur_end - cur_start
                cur_start, cur_end = s, e
        length += cur_end - cur_start
        return length

    for x, typ, y1, y2 in events:
        total += (x - prev_x) * active_y_length()
        if typ == 1:
            active.append((y1, y2))
        else:
            active.remove((y1, y2))
        prev_x = x

    return total

