        for (int c = 0; c < n; c++) { dfs(board, 0, c); dfs(board, m-1, c); }
        for (int r = 0; r < m; r++)
            for (int c = 0; c < n; c++)
                board[r][c] = board[r][c] == 'S' ? 'O' : 'X';
    }
